<template>
  <div class="carousel-wrapper">
    <div
      class="carousel-content"
      :style="{ transform: 'translateX(' + position + 'px)' }"
    >
      <div
        v-for="(product, index) in products"
        :key="index"
        class="carousel-slide"
      >
        <div class="slider">
          <img
            :key="product.url"
            :src="product.url"
            :alt="`imagen-${product.title}`"
            class="slider_img"
          />
        </div>
        <p>{{ product.title }}</p>
      </div>
    </div>
    <div class="carousel-navigation">
      <!-- <font-awesome-icon :icon="['fas', 'chevron-right']" /> -->
      
      <!-- <font-awesome-icon :icon="['far', 'chevron-right']" style="color: #000000;" @click="nextProduct" /> -->
      <button class="carousel-btn-d" @click="nextProduct()">&gt;</button>
    </div>
  </div>
</template>

<style lang="scss" scoped>
.carousel-wrapper {
  position: relative;
  overflow: hidden;
  max-height: 300px;
  .carousel-content {
    display: flex;
    flex-wrap: nowrap;

    .carousel-slide {
      flex-shrink: 0;
      max-width: 100%;

      .slider {
        width: 100%;
        height: 250px;
      }

      .slider_img {
        width: 100%;
        height: auto;
      }
    }
  }
}
.carousel-navigation {
  background-color: rgb(133, 216, 216, 0);
  position: absolute;
  top: 0;
  height: 100%;
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  // padding: 0px;

  // max-width:100%;
}
.carousel-btn-i,
.carousel-btn-d {
  background-color: rgba(0, 0, 0, 0.2);
  color: white;
  border: none;
  padding: 12px;
  font-size: 16px;
  font-weight: bolder;
  cursor: pointer;
  // margin: 0 ;
  /* Espacio entre los botones */
}
</style>
<script>
import { mapState } from "vuex";

export default {
  computed: {
    ...mapState(["products"]),
    isLoading() {
      return this.products.length === 0;
    },
    numGames() {
      return this.products ? this.products.length : 0;
    },
    shouldTransition() {
      return this.contador > 0;
    },
  },

  data() {
    return {
      position: 0,
    };
  },

  methods: {
    prevProduct() {
      let newPositionPrev = this.position + this.slideWidth();
      if (newPositionPrev <= 0) {
        this.position = newPositionPrev;
      } else {
        this.position = (this.numGames - 1) * this.slideWidth() * -1;
      }
    },

    nextProduct() {
      const MAXSLIDE = (this.numGames - 1) * this.slideWidth() * -1;
      let newPositionNext = this.position - this.slideWidth();
      if (newPositionNext >= MAXSLIDE && newPositionNext <= 0) {
        this.position -= this.slideWidth();
      } else {
        this.position = 0;
      }
    },

    slideWidth() {
      const slideElement = document.querySelector(".carousel-slide");
      return slideElement.clientWidth;
    },
  },
};
</script>
